import sailpoint.object.Identity;
import org.ascn.utils.Common;

String RULE_NAME = "ASCN-CyberArk-Escalation-EmailRecipient";
String LOG_NAME = "sailpoint.ascension.emailRecipientCyberArkAttestation";

Common.info(LOG_NAME,"Entering " + RULE_NAME);
if (null != item && null != item.getNotificationOwner(context))
{
 Identity snrManagerIdentity = item.getNotificationOwner(context);
 if(null != snrManagerIdentity && null != snrManagerIdentity.getManager())
    return snrManagerIdentity.getManager().getName();
}
Common.info(LOG_NAME,"Exiting " + RULE_NAME);
return "ASCN-CyberArk-Attestation-Reviewer";
